const PARAMS_SCHEMA = {
  gmail_search: { required: [], optional: ['q', 'max_results', 'label'] },
  gmail_read: { required: ['message_id'], optional: [] },
  gmail_send: { required: ['to', 'subject', 'body'], optional: ['cc', 'bcc'] },
  gmail_delete: { required: ['message_id'], optional: [] },
  calendar_list: { required: [], optional: ['time_min', 'time_max', 'max_results'] },
  calendar_create: { required: ['summary', 'start', 'end'], optional: ['description', 'location'] },
  calendar_delete: { required: ['event_id'], optional: [] },
  drive_list: { required: [], optional: ['folder_id', 'max_results', 'query'] },
  drive_search: { required: ['query'], optional: ['max_results'] },
  drive_upload: { required: ['name', 'content'], optional: ['folder_id', 'mimeType'] },
  drive_download: { required: ['file_id'], optional: [] },
  drive_delete: { required: ['file_id'], optional: [] },
  contacts_list: { required: [], optional: ['max_results'] },
  contacts_search: { required: ['query'], optional: ['max_results'] },
  contacts_create: { required: ['name'], optional: ['email', 'phone'] },
  docs_create: { required: ['title'], optional: ['content'] },
  docs_read: { required: ['document_id'], optional: [] },
  docs_edit: { required: ['document_id', 'content'], optional: [] },
  slides_create: { required: ['title'], optional: ['slides_count'] },
  sheets_read: { required: ['spreadsheet_id', 'range'], optional: [] },
  sheets_write: { required: ['spreadsheet_id', 'range', 'values'], optional: [] },
  sheets_create: { required: ['title'], optional: [] },
  tasks_list: { required: [], optional: ['tasklist_id', 'max_results'] },
  tasks_create: { required: ['title'], optional: ['due', 'notes', 'tasklist_id'] },
  tasks_update: { required: ['task_id', 'title'], optional: ['status', 'due', 'tasklist_id'] },
  tasks_delete: { required: ['task_id'], optional: ['tasklist_id'] },
  knowledge_query: { required: ['query'], optional: ['source'] },
  general_chat: { required: [], optional: ['context'] }
};

const jarvisLog = (level, message, meta = {}) => {
  const levels = { debug: 0, info: 1, warn: 2, error: 3 };
  const configLevel = ($env.LOG_LEVEL || 'info').toLowerCase();
  if (levels[level] >= (levels[configLevel] ?? 1)) {
    console[level === 'error' ? 'error' : level === 'warn' ? 'warn' : 'log'](
      JSON.stringify({ timestamp: new Date().toISOString(), level, traceId: $json.sessionId || 'unknown', workflow: 'intent-classifier', message, meta })
    );
  }
};

let raw = '';
try {
  raw = $json.choices?.[0]?.message?.content || '{}';
  raw = raw.replace(/```json|```/g, '').trim();
} catch (e) {
  raw = '{}';
}
let decision;
try {
  decision = JSON.parse(raw);
} catch (e) {
  decision = { intent: 'general_chat', confidence: 1.0, params: {} };
}

const VALID_INTENTS = Object.keys(PARAMS_SCHEMA);
if (!VALID_INTENTS.includes(decision.intent)) {
  decision.intent = 'general_chat';
  decision.confidence = 0.5;
}

const schema = PARAMS_SCHEMA[decision.intent];
let params = decision.params || {};
if (schema) {
  const allowed = new Set([...schema.required, ...schema.optional]);
  const cleaned = {};
  for (const [key, val] of Object.entries(params)) {
    if (allowed.has(key)) {
      cleaned[key] = val;
    } else {
      jarvisLog('warn', 'Stripped hallucinated param', { intent: decision.intent, param: key, value: val });
    }
  }
  for (const key of schema.required) {
    if (cleaned[key] === undefined || cleaned[key] === null || cleaned[key] === '') {
      cleaned[key] = null;
      jarvisLog('warn', 'Missing required param set to null', { intent: decision.intent, param: key });
    }
  }
  params = cleaned;
}

return [{ json: { ...$input.item.json, intent: decision.intent, intentConfidence: decision.confidence || 0, intentParams: params } }];
